// Netlify Function: generate-angebot
// Generates a Signium Angebot DOCX from structured input JSON
// Deploy to: netlify/functions/generate-angebot.js

import {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  ImageRun, Header, AlignmentType, BorderStyle, WidthType, ShadingType,
  VerticalAlign, LevelFormat, PageBreak
} from 'docx';

// ─── EMBEDDED IMAGES (base64) ─────────────────────────────────────────────────
// Replace these strings with actual base64 content from img_b64_constants.json
const IMG_SIG_B64  = '';
const IMG_LOGO_B64 = '';

// ─── COLORS ───────────────────────────────────────────────────────────────────
const NAVY   = '081D4D';
const ORANGE = 'FF6A42';
const WHITE  = 'FFFFFF';
const LIGHT  = 'F0F4F9';

// ─── HELPERS ──────────────────────────────────────────────────────────────────
const noBorder  = { style: BorderStyle.NONE, size: 0, color: 'FFFFFF' };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

function para(text, opts = {}) {
  return new Paragraph({
    spacing: { before: opts.before ?? 80, after: opts.after ?? 80 },
    alignment: opts.align ?? AlignmentType.LEFT,
    children: [new TextRun({
      text: text || '',
      font: 'Gill Sans MT',
      size: opts.size ?? 20,
      bold: opts.bold ?? false,
      color: opts.color ?? '000000',
      italics: opts.italic ?? false,
    })]
  });
}

function heading(text) {
  return new Paragraph({
    spacing: { before: 200, after: 100 },
    children: [new TextRun({
      text: text.toUpperCase(),
      font: 'Gill Sans MT',
      size: 22,
      bold: true,
      color: NAVY,
    })]
  });
}

function subHeading(text) {
  return new Paragraph({
    spacing: { before: 140, after: 60 },
    children: [new TextRun({ text, font: 'Gill Sans MT', size: 21, bold: true, color: NAVY })]
  });
}

function hr() {
  return new Paragraph({
    spacing: { before: 40, after: 60 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: NAVY, space: 1 } },
    children: []
  });
}

function bulletPara(text) {
  return new Paragraph({
    numbering: { reference: 'bullets', level: 0 },
    spacing: { before: 40, after: 40 },
    children: [new TextRun({ text: text || '', font: 'Gill Sans MT', size: 20 })]
  });
}

function emptyLine() { return para('', { before: 30, after: 30 }); }

function textBlock(text) {
  const lines = (text || '').split('\n').filter(l => l.trim());
  return lines.map(line => {
    const clean = line.replace(/^[•\-]\s*/, '');
    return (line.startsWith('•') || line.startsWith('-'))
      ? bulletPara(clean)
      : para(clean, { before: 50, after: 50 });
  });
}

