// ─── COVER TABLE ──────────────────────────────────────────────────────────────
function makeCoverTable(d, lang, IMG_SIG, IMG_LOGO) {
  const isDE = lang === 'DE';
  const cellL = (children) => new TableCell({
    borders: noBorders,
    shading: { fill: NAVY, type: ShadingType.CLEAR },
    width: { size: 5400, type: WidthType.DXA },
    margins: { top: 400, bottom: 600, left: 500, right: 400 },
    verticalAlign: VerticalAlign.TOP,
    children,
  });
  const cellR = (children) => new TableCell({
    borders: noBorders,
    shading: { fill: WHITE, type: ShadingType.CLEAR },
    width: { size: 4360, type: WidthType.DXA },
    margins: { top: 400, bottom: 600, left: 400, right: 300 },
    verticalAlign: VerticalAlign.TOP,
    children,
  });
  const lbl = (t) => new Paragraph({ spacing:{before:200,after:40}, children:[new TextRun({text:t, font:'Gill Sans MT', size:17, color:'8899BB'})] });
  const val = (t, bold=false) => new Paragraph({ spacing:{after:50}, children:[new TextRun({text:t||'', font:'Gill Sans MT', size:22, bold, color:WHITE})] });
  const valR = (t, bold=false) => new Paragraph({ spacing:{after:50}, children:[new TextRun({text:t||'', font:'Gill Sans MT', size:21, bold, color:NAVY})] });

  return new Table({
    width: { size: 9760, type: WidthType.DXA },
    columnWidths: [5400, 4360],
    rows: [new TableRow({ children: [
      cellL([
        new Paragraph({ spacing:{after:400}, children:[new ImageRun({ data:IMG_LOGO, transformation:{width:150,height:48}, type:'png'})] }),
        lbl(isDE ? 'ANGEBOT / PROJEKTPLAN' : 'PROPOSAL'),
        val(d.positionTitle, true),
        lbl(isDE ? 'KLIENT' : 'CLIENT'),
        val(d.clientCompany),
        lbl(isDE ? 'DATUM' : 'DATE'),
        val(d.date),
      ]),
      cellR([
        lbl(isDE ? 'UNTERBREITET VON' : 'SUBMITTED BY'),
        valR('Dr. Sami Hamid', true),
        new Paragraph({spacing:{after:40}, children:[new TextRun({text:'Managing Partner', font:'Gill Sans MT', size:19, color:'444444'})]}),
        new Paragraph({spacing:{before:120,after:30}, children:[new TextRun({text:'t  +43-1-225 635 452', font:'Gill Sans MT', size:18, color:'555555'})]}),
        new Paragraph({spacing:{after:30}, children:[new TextRun({text:'m  +43-664-4568862', font:'Gill Sans MT', size:18, color:'555555'})]}),
        new Paragraph({spacing:{after:30}, children:[new TextRun({text:'e  sami.hamid@signium.com', font:'Gill Sans MT', size:18, color:NAVY})]}),
        new Paragraph({spacing:{before:300,after:40}, children:[new ImageRun({ data:IMG_SIG, transformation:{width:110,height:65}, type:'jpg'})]}),
      ]),
    ]})]
  });
}

// ─── HONORAR TABLE ────────────────────────────────────────────────────────────
function makeHonorarTable(d, lang) {
  const isDE = lang === 'DE';
  const border = { style: BorderStyle.SINGLE, size: 1, color: 'CCCCCC' };
  const borders = { top: border, bottom: border, left: border, right: border };
  const hCell = (t) => new TableCell({
    borders, shading:{fill:LIGHT, type:ShadingType.CLEAR},
    margins:{top:80,bottom:80,left:120,right:120},
    children:[new Paragraph({children:[new TextRun({text:t, font:'Gill Sans MT', size:19, bold:true, color:NAVY})]})]
  });
  const dCell = (t, w) => new TableCell({
    borders, width:{size:w,type:WidthType.DXA},
    margins:{top:80,bottom:80,left:120,right:120},
    children:[new Paragraph({children:[new TextRun({text:t||'', font:'Gill Sans MT', size:19})]})]
  });

  return new Table({
    width: { size: 9760, type: WidthType.DXA },
    columnWidths: [700, 6100, 2960],
    rows: [
      new TableRow({ children: [hCell(isDE?'Rate':'No.'), hCell(isDE?'Fälligkeit':'Due date'), hCell(isDE?'Betrag':'Amount')] }),
      new TableRow({ children: [dCell('1.',700), dCell(isDE?'Fällig bei Auftragserteilung':'Due upon commencement of assignment',6100), dCell(d.rate1||'',2960)] }),
      new TableRow({ children: [dCell('2.',700), dCell(isDE?'Fällig nach Präsentation der ersten Kandidaten':'Due upon presentation of shortlisted candidates',6100), dCell(d.rate2||'',2960)] }),
      new TableRow({ children: [dCell('3.',700), dCell(isDE?'Fällig nach erfolgreichem Abschluss / Vertragsunterzeichnung':'Due upon successful completion / contract signing',6100), dCell(d.rate3||isDE?'Anpassung gem. 1/3-Regelung':'Adjustment per 1/3 rule',2960)] }),
    ]
  });
}

// ─── SIGNATURE TABLE ──────────────────────────────────────────────────────────
function makeSignatureTable(d, lang) {
  const isDE = lang === 'DE';
  const lineTop = { style: BorderStyle.SINGLE, size: 1, color: 'AAAAAA' };
  const topBorder = { top: lineTop, bottom: noBorder, left: noBorder, right: noBorder };
  return new Table({
    width: { size: 9760, type: WidthType.DXA },
    columnWidths: [4680, 5080],
    rows: [new TableRow({ children: [
      new TableCell({ borders: topBorder, width:{size:4680,type:WidthType.DXA}, margins:{top:80,bottom:0,left:0,right:200},
        children:[
          para('Dr. Sami Hamid', { bold:true, size:19 }),
          para('Managing Partner, Vienna / Bucharest', { size:18, color:'666666' }),
        ]}),
      new TableCell({ borders: topBorder, width:{size:5080,type:WidthType.DXA}, margins:{top:80,bottom:0,left:200,right:0},
        children:[
          para(d.clientSignatoryName || (isDE?'[Name Klient]':'[Client Name]'), { bold:true, size:19 }),
          para(d.clientSignatoryTitle || (isDE?'[Funktion]':'[Title]'), { size:18, color:'666666' }),
        ]}),
    ]})]
  });
}

// ─── MAIN BUILD FUNCTION ──────────────────────────────────────────────────────
async function buildAngebot(input) {
  const d = input;
  const lang = d.language || 'DE';
  const isDE = lang === 'DE';

  const IMG_SIG  = Buffer.from(IMG_SIG_B64,  'base64');
  const IMG_LOGO = Buffer.from(IMG_LOGO_B64, 'base64');

  // Merge user-provided fixed texts with defaults
  const defaults = getFixedDefaults(lang);
  const fixed = {};
  for (const key of Object.keys(defaults)) {
    fixed[key] = (d.fixedTexts && d.fixedTexts[key] && d.fixedTexts[key].trim())
      ? d.fixedTexts[key]
      : defaults[key];
  }

  const children = [
    // ── COVER ──
    makeCoverTable(d, lang, IMG_SIG, IMG_LOGO),
    new Paragraph({ children: [new PageBreak()] }),

    // ── INTRO LETTER ──
    para(d.date||'', { color:'555555' }),
    emptyLine(),
    para(isDE ? 'persönlich/vertraulich' : 'PRIVATE AND CONFIDENTIAL', { bold:true }),
    emptyLine(),
    para(d.clientContactName||''),
    para(d.clientCompany||''),
    para(d.clientAddress||''),
    para(d.clientCity||''),
    emptyLine(),
    para(`${isDE?'Per Mail: ':'By Email: '}${d.clientEmail||''}`),
    emptyLine(),
    para(`${isDE?'Sehr geehrte':'Dear'} ${d.clientSalutation||''} ${d.clientContactLastName||''},`),
    emptyLine(),
    para(isDE
      ? 'Wie vereinbart möchten wir Ihnen sehr gerne unser Angebot unterbreiten, Sie bei der Suche nach und Auswahl eines'
      : `Thank you for considering Signium as partner for Executive Search services for the position`),
    emptyLine(),
    new Paragraph({ alignment: AlignmentType.CENTER, spacing:{before:60,after:60}, children:[new TextRun({text:d.positionTitle||'', font:'Gill Sans MT', size:24, bold:true, color:NAVY})] }),
    emptyLine(),
    para(isDE
      ? 'zu unterstützen. Im Folgenden möchte ich Ihnen unser Angebot darstellen, das sich in drei Abschnitte gliedert: (1) Beratungsleistungen und Vorgehensweise, (2) das Team unseres gemeinsamen Projektes sowie (3) unsere Honorarkonditionen und Grundsätze der Zusammenarbeit.'
      : `with ${d.clientCompany||''}. Our proposal is divided into: (1) Purpose and approach, (2) Your Signium team, (3) Commercial proposal, (4) Terms & Conditions.`),

    new Paragraph({ children: [new PageBreak()] }),

    // ── 1. COMPANY PROFILE ──
    heading(isDE ? '1. Das Unternehmensprofil' : '1. Company Profile'),
    hr(),
    ...textBlock(d.companyProfile||''),
    emptyLine(),

    heading(isDE ? 'Die Position' : 'The Role'),
    hr(),
    ...textBlock(d.positionDescription||''),
    emptyLine(),

    heading(isDE ? 'Warum Signium?' : 'Why Signium?'),
    hr(),
    ...textBlock(fixed.whySignium),
    emptyLine(),

    new Paragraph({ children: [new PageBreak()] }),

    // ── 2. APPROACH ──
    heading(isDE ? '2. Beratungsleistungen & Vorgehensweise' : '2. Purpose and Approach'),
    hr(),
    emptyLine(),

    subHeading(isDE ? 'Phase I: Identifikation und Direktansprache' : 'Phase I: Candidate Identification and Mapping'),
    ...textBlock(fixed.phase1),
    emptyLine(),

    new Paragraph({ spacing:{before:100,after:60}, children:[new TextRun({text: isDE?'Suchfelder:':'Search Criteria:', font:'Gill Sans MT', size:20, bold:true})] }),
    new Paragraph({ spacing:{before:60,after:20}, children:[new TextRun({text: isDE?'Funktions-Targets:':'Functional Targets:', font:'Gill Sans MT', size:19, bold:true, color:'333333'})] }),
    ...(d.functionalTargets||[]).map(t => bulletPara(t)),
    emptyLine(),
    new Paragraph({ spacing:{before:60,after:20}, children:[new TextRun({text: isDE?'Unternehmens-Targets / Branchen:':'Industry / Company Targets:', font:'Gill Sans MT', size:19, bold:true, color:'333333'})] }),
    ...(d.industryTargets||[]).map(t => bulletPara(t)),
    emptyLine(),
    new Paragraph({ spacing:{before:60,after:20}, children:[new TextRun({text: isDE?'Geographischer Search Fokus:':'Geographic Search Focus:', font:'Gill Sans MT', size:19, bold:true, color:'333333'})] }),
    ...(d.geoTargets||[]).map(t => bulletPara(t)),
    emptyLine(),

    subHeading(isDE ? 'Phase II: Kandidatenbeurteilung und Präsentation' : 'Phase II: Candidate Evaluation and Shortlist'),
    ...textBlock(fixed.phase2),
    emptyLine(),

    subHeading(isDE ? 'Phase III: Interview, Referenzen und Vertragsverhandlungen' : 'Phase III: Client Interviews, Referencing and Closure'),
    ...textBlock(fixed.phase3),
    emptyLine(),

    new Paragraph({ children: [new PageBreak()] }),

    // ── 3. TEAM ──
    heading(isDE ? '3. Ihr Signium Team' : '3. Your Signium Team'),
    hr(),
    new Table({
      width: { size: 9760, type: WidthType.DXA },
      columnWidths: [5000, 4760],
      rows: [new TableRow({ children: [
        new TableCell({ borders: noBorders, width:{size:5000,type:WidthType.DXA}, margins:{top:80,bottom:80,left:0,right:200},
          children:[
            para('Dr. Sami Hamid', { bold:true, size:21, color:NAVY }),
            para('Managing Partner', { size:19, color:'444444' }),
          ]}),
        new TableCell({ borders: noBorders, width:{size:4760,type:WidthType.DXA}, margins:{top:80,bottom:80,left:200,right:0},
          children:[
            para('Office: +43-1-225 635 452', { size:19 }),
            para('Mobile: +43-664-4568862', { size:19 }),
            para('Email: sami.hamid@signium.com', { size:19 }),
          ]}),
      ]})]
    }),
    emptyLine(),

    // Additional team members
    ...(d.additionalTeam||[]).flatMap(m => [
      new Table({
        width: { size: 9760, type: WidthType.DXA },
        columnWidths: [5000, 4760],
        rows: [new TableRow({ children: [
          new TableCell({ borders: noBorders, width:{size:5000,type:WidthType.DXA}, margins:{top:80,bottom:80,left:0,right:200},
            children:[ para(m.name||'', {bold:true,size:21,color:NAVY}), para(m.title||'', {size:19,color:'444444'}) ]}),
          new TableCell({ borders: noBorders, width:{size:4760,type:WidthType.DXA}, margins:{top:80,bottom:80,left:200,right:0},
            children:[ para(m.office||'', {size:19}), para(m.email||'', {size:19}) ]}),
        ]})]
      }),
      emptyLine(),
    ]),

    new Paragraph({ children: [new PageBreak()] }),

    // ── 4. HONORAR ──
    heading(isDE ? '4. Honorarkonditionen' : '3. Commercial Proposal'),
    hr(),
    ...textBlock(fixed.honorarStruktur),
    emptyLine(),
    ...(d.honorarDetails ? [...textBlock(d.honorarDetails), emptyLine()] : []),
    makeHonorarTable(d, lang),
    emptyLine(),

    subHeading(isDE ? 'Reise- und Verwaltungskosten' : 'Administration Expenses'),
    ...textBlock(fixed.reisekosten),
    emptyLine(),
    subHeading(isDE ? 'Zusatzbesetzungen' : 'Deferred Hiring / Third Party Employment'),
    ...textBlock(fixed.zusatzbesetzungen),
    emptyLine(),
    subHeading(isDE ? 'Zeitplan & Nachbesetzungsgarantie' : 'Timeline & Guarantee'),
    ...textBlock(fixed.garantie),
    emptyLine(),

    new Paragraph({ children: [new PageBreak()] }),

    // ── 5. T&C ──
    heading(isDE ? '5. Grundsätze der Zusammenarbeit' : '4. General Terms & Conditions'),
    hr(),
    subHeading(isDE ? 'Vertraulichkeit & Ethik' : 'Confidentiality, Privacy & Integrity'),
    ...textBlock(fixed.vertraulichkeit),
    emptyLine(),
    subHeading('Off Limits'),
    ...textBlock(fixed.offLimits),
    emptyLine(),
    subHeading(isDE ? 'Kündigung' : 'Cancellation Policy'),
    ...textBlock(fixed.kuendigung),
    emptyLine(),

    new Paragraph({ children: [new PageBreak()] }),

    // ── CLOSING ──
    heading(isDE ? 'Auftragsbestätigung' : 'Confirmation of Assignment'),
    hr(),
    para(isDE
      ? 'Aufgrund unserer über 30-jährigen Expertise, unserer professionellen und strukturierten Vorgehensweise sowie zahlreicher erfolgreicher Besetzungen bieten wir Ihnen ein hohes Maß an Sicherheit. Wir freuen uns sehr auf eine mögliche Zusammenarbeit.'
      : 'Thank you for this opportunity. We would be delighted to answer any questions arising from this proposal and look forward to working with you on this important assignment.',
      { before:80, after:100 }),
    emptyLine(),
    para(isDE ? 'Mit freundlichen Grüßen' : 'Yours sincerely,'),
    emptyLine(),
    new Paragraph({ children:[new ImageRun({ data:IMG_SIG, transformation:{width:120,height:71}, type:'jpg'})] }),
    para('Dr. Sami Hamid', { bold:true }),
    para('Managing Partner', { color:'555555', size:19 }),
    emptyLine(),
    emptyLine(),
    makeSignatureTable(d, lang),
    emptyLine(),
    para(`${isDE?'Datum':'Date'}: ${d.date||''}`, { size:18, color:'777777' }),
  ];

  const doc = new Document({
    numbering: {
      config: [{
        reference: 'bullets',
        levels: [{ level:0, format:LevelFormat.BULLET, text:'•', alignment:AlignmentType.LEFT,
          style:{ paragraph:{ indent:{ left:560, hanging:280 } } } }]
      }]
    },
    styles: {
      default: { document: { run: { font:'Gill Sans MT', size:20 } } },
    },
    sections: [{
      properties: {
        page: {
          size: { width:11906, height:16838 },
          margin: { top:1134, right:1134, bottom:1134, left:1134 }
        }
      },
      headers: {
        default: new Header({
          children: [
            new Table({
              width:{ size:9638, type:WidthType.DXA },
              columnWidths:[7500,2138],
              rows:[new TableRow({ children:[
                new TableCell({ borders:noBorders, width:{size:7500,type:WidthType.DXA}, verticalAlign:VerticalAlign.CENTER,
                  children:[new Paragraph({ children:[new TextRun({ text:`SIGNIUM | ${(d.positionTitle||'').toUpperCase()} | ${(d.clientCompany||'').toUpperCase()}`, font:'Gill Sans MT', size:16, color:'999999'})] })] }),
                new TableCell({ borders:noBorders, width:{size:2138,type:WidthType.DXA}, verticalAlign:VerticalAlign.CENTER,
                  children:[new Paragraph({ alignment:AlignmentType.RIGHT, children:[new ImageRun({ data:IMG_LOGO, transformation:{width:80,height:26}, type:'png'})] })] }),
              ]})]
            }),
            new Paragraph({ border:{ bottom:{ style:BorderStyle.SINGLE, size:4, color:ORANGE, space:1 }}, children:[] }),
          ]
        })
      },
      children,
    }]
  });

  return await Packer.toBuffer(doc);
}

// ─── NETLIFY HANDLER ──────────────────────────────────────────────────────────
export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  const input = req.body;

  try {
    const buffer = await buildAngebot(input);
    const b64 = buffer.toString('base64');
    const filename = `Signium_Angebot_${(input.clientCompany||'Klient').replace(/\s+/g,'_')}_${(input.positionTitle||'Position').replace(/\s+/g,'_').replace(/[^a-zA-Z0-9_\-äöüÄÖÜ]/g,'')}.docx`;

    return res.status(200).json({ docx: b64, filename });
  } catch (err) {
    console.error('Angebot generation error:', err);
    return res.status(500).json({ error: err.message });
  }
};
